// src/routes/AppRoutes.js
import React from "react";
import { Routes, Route, Navigate } from "react-router-dom";

// Auth Pages
import Login from "../pages/auth/Login";
import Register from "../pages/auth/Register";

// Dashboard Pages
import AdminDashboard from "../pages/dashboard/AdminDashboard";
import InstructorDashboard from "../pages/dashboard/InstructorDashboard";
import StudentDashboard from "../pages/dashboard/StudentDashboard";
import ContentDashboard from "../pages/dashboard/ContentDashboard";

// Protected Route Wrapper
import Protected from "../components/Protected";

// Centralized 404 Page (Fallback for undefined routes)
const NotFound = () => (
  <div
    style={{
      display: "flex",
      flexDirection: "column",
      justifyContent: "center",
      alignItems: "center",
      height: "80vh",
      textAlign: "center",
      padding: "20px",
      fontFamily: "'Segoe UI', Tahoma, Geneva, Verdana, sans-serif",
    }}
  >
    <h1
      style={{
        fontSize: "2.5rem",
        color: "#ef4444",
        marginBottom: "15px",
        fontWeight: "700",
      }}
    >
      404 - Page Not Found
    </h1>
    <p style={{ color: "#374151", fontSize: "1.1rem", marginBottom: "20px" }}>
      The page you are looking for does not exist or has been moved.
    </p>
    <a
      href="/"
      style={{
        color: "#a71010",
        fontWeight: "600",
        textDecoration: "underline",
        cursor: "pointer",
        transition: "color 0.3s ease",
      }}
      onMouseOver={(e) => (e.target.style.color = "#7a0c0c")}
      onMouseOut={(e) => (e.target.style.color = "#a71010")}
    >
      Return to Home
    </a>
  </div>
);

const AppRoutes = () => {
  return (
    <Routes>
      {/* Public Routes: Accessible to all users */}
      <Route path="/" element={<Login />} />
      <Route path="/register" element={<Register />} />

      {/* Protected Routes: Access controlled based on roles */}
      <Route
        path="/admin"
        element={
          <Protected allowedRoles={["admin"]}>
            <AdminDashboard />
          </Protected>
        }
      />
      <Route
        path="/instructor"
        element={
          <Protected allowedRoles={["instructor"]}>
            <InstructorDashboard />
          </Protected>
        }
      />
      <Route
        path="/student"
        element={
          <Protected allowedRoles={["student"]}>
            <StudentDashboard />
          </Protected>
        }
      />
      <Route
        path="/content"
        element={
          <Protected allowedRoles={["content"]}>
            <ContentDashboard />
          </Protected>
        }
      />

      {/* Fallback Route for undefined URLs (404 page) */}
      <Route path="*" element={<NotFound />} />
    </Routes>
  );
};

export default AppRoutes;
